1493:
SELECT AVG(CASE WHEN Consumption > 528.3 THEN 1 ELSE 0 END) * 100 AS percentage 
FROM yearmonth 
WHERE Date = '201202';

1201:
SELECT CAST(SUM(CASE WHEN SEX = 'F' THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(*) AS percentage 
FROM Patient 
WHERE strftime('%Y', Birthday) = '1980' AND Diagnosis = 'RA';

1251:
SELECT COUNT(DISTINCT L.ID) AS patient_count 
FROM Laboratory L 
WHERE L.IGG >= 2000;

1035:
SELECT DISTINCT team_fifa_api_id 
FROM Team_Attributes 
WHERE buildUpPlaySpeed > 50 AND buildUpPlaySpeed < 60;

1078:
SELECT player_name, birthday
FROM Player
WHERE player_name IN ('Aaron Lennon', 'Abdelaziz Barrada');

945:
SELECT COUNT(*) AS circuit_count
FROM circuits
WHERE country = 'Australia' AND location = 'Adelaide';

737:
SELECT r.race FROM superhero s
JOIN race r ON s.race_id = r.id
WHERE s.superhero_name = 'Copycat';

765:
SELECT COUNT(*) FROM hero_power hp 
JOIN superpower sp ON hp.power_id = sp.id 
WHERE sp.power_name = 'Stealth';

800:
SELECT ROUND((SUM(CASE WHEN c.colour = 'Blue' THEN 1 ELSE 0 END) * 100.0 / COUNT(s.superhero_name)), 2) AS blue_eyes_percentage 
FROM superhero s 
INNER JOIN colour c ON s.eye_colour_id = c.id;

801:
SELECT CAST(SUM(CASE WHEN g.gender = 'Male' THEN 1 ELSE 0 END) AS REAL) / NULLIF(CAST(SUM(CASE WHEN g.gender = 'Female' THEN 1 ELSE 0 END) AS REAL), 0) as ratio 
FROM superhero s 
JOIN gender g ON s.gender_id = g.id;

683:
SELECT CAST(SUM(CASE WHEN strftime('%Y', p.CreaionDate) = '2011' AND u.Reputation > 1000 THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(p.Id) AS percentage 
FROM posts p 
JOIN users u ON p.OwnerUserId = u.Id;

687:
SELECT COUNT(*) FROM comments c 
JOIN posts p ON c.PostId = p.Id 
WHERE p.Score = (SELECT MAX(Score) FROM posts);

383:
SELECT COUNT(*) FROM cards c 
JOIN legalities l ON c.uuid = l.uuid 
WHERE l.status = 'Banned' AND c.borderColor = 'white';

215:
SELECT 
    (SELECT COUNT(*) FROM atom a WHERE a.element = 'i' AND a.molecule_id IN (SELECT DISTINCT m.molecule_id FROM molecule m JOIN bond b ON m.molecule_id = b.molecule_id WHERE b.bond_type = '-')) AS iodine_count,
    (SELECT COUNT(*) FROM atom a WHERE a.element = 's' AND a.molecule_id IN (SELECT DISTINCT m.molecule_id FROM molecule m JOIN bond b ON m.molecule_id = b.molecule_id WHERE b.bond_type = '-')) AS sulfur_count;

